frappe.ui.form.on('Expense Entry', {
    company(frm) {
        // Check if a company is selected
        if (frm.doc.company) {
            // Fetch the default currency for the selected company
            frappe.db.get_value('Company', frm.doc.company, 'default_currency', (r) => {
                if (r && r.default_currency) {
                    const currency = r.default_currency;

                    // Update the label of the 'paid_amount' field
                    const paid_amount_label = `Paid Amount (${currency})`;
                    frm.set_df_property('paid_amount', 'label', paid_amount_label);

                    // Update the label of the 'total_taxable_amount' field
                    const taxable_amount_label = `Total Taxable Amount (${currency})`;
                    frm.set_df_property('total_taxable_amount', 'label', taxable_amount_label);

                    // Update the label of the 'total_vat' field
                    const vat_label = `Total VAT (${currency})`;
                    frm.set_df_property('total_vat', 'label', vat_label);
                }
            });
        }
    },

    onload(frm) {
        // When the form loads, set the labels based on the selected company if already set
        if (frm.doc.company) {
            frappe.db.get_value('Company', frm.doc.company, 'default_currency', (r) => {
                if (r && r.default_currency) {
                    const currency = r.default_currency;

                    // Set the labels dynamically for the fields
                    const paid_amount_label = `Paid Amount (${currency})`;
                    frm.set_df_property('paid_amount', 'label', paid_amount_label);

                    const taxable_amount_label = `Total Taxable Amount (${currency})`;
                    frm.set_df_property('total_taxable_amount', 'label', taxable_amount_label);

                    const vat_label = `Total VAT (${currency})`;
                    frm.set_df_property('total_vat', 'label', vat_label);
                }
            });
        }
    }
});

frappe.ui.form.on('Expense Entry', {
    // Trigger before saving the form to ensure all rows in the child table are updated
    before_save: function (frm) {
        frm.fields_dict.expense_entry_account.grid.grid_rows.forEach(row => {
            calculate_vat_amount(row.doc, frm);
        });
    }
});

frappe.ui.form.on('expense_entry_account', {
    // Trigger when taxable_amount changes
    taxable_amount: function (frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.taxable_amount) {
            calculate_vat_amount(row, frm);
        }
    },

    // Trigger when vat_rate changes
    vat_rate: function (frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.vat_rate) {
            calculate_vat_amount(row, frm);
        }
    }
});

// Helper function to calculate VAT Amount
function calculate_vat_amount(row, frm) {
    if (row.taxable_amount && row.vat_rate) {
        // Calculate VAT Amount as taxable_amount * vat_rate / 100
        let vat_amount = (row.taxable_amount * row.vat_rate) / 100;
        frappe.model.set_value(row.doctype, row.name, 'vat_amount', vat_amount);
    } else {
        // Clear vat_amount if taxable_amount or vat_rate is missing
        frappe.model.set_value(row.doctype, row.name, 'vat_amount', 0);
    }
}

frappe.ui.form.on('Expense Entry', {
    before_save: function (frm) {
        if (!frm.doc.naming_series && frm.doc.posting_date) {
            const date = frappe.datetime.str_to_obj(frm.doc.posting_date);
            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const prefix = `EXPE-${year}-${month}-`;

            frappe.call({
                method: "frappe.client.get_list",
                args: {
                    doctype: "Expense Entry",
                    fields: ["name"],
                    filters: [["name", "like", `${prefix}%`]],
                    order_by: "name desc",
                    limit_page_length: 1
                },
                callback: function (r) {
                    let next_number = 1;
                    if (r.message.length) {
                        const last_number = parseInt(r.message[0].name.split("-")[3]);
                        if (!isNaN(last_number)) {
                            next_number = last_number + 1;
                        }
                    }
                    const new_name = prefix + String(next_number).padStart(5, '0');
                    frm.set_value("naming_series", new_name);
                }
            });
        }
    }
});

frappe.ui.form.on('Expense Entry', {
    // Trigger before saving the document
    before_save: function (frm) {
        update_totals(frm);
        enhance_paid_amount_field(frm);
    },

    // Trigger on form refresh to ensure totals and styles are updated
    refresh: function (frm) {
        update_totals(frm);
        enhance_paid_amount_field(frm);
    }
});

frappe.ui.form.on('expense_entry_account', {
    // Trigger when taxable_amount changes
    taxable_amount: function (frm, cdt, cdn) {
        update_totals(frm);
    },

    // Trigger when vat_amount changes
    vat_amount: function (frm, cdt, cdn) {
        update_totals(frm);
    }
});

// Helper Function to Update Totals
function update_totals(frm) {
    let total_taxable_amount = 0;
    let total_vat = 0;

    // Loop through all rows in the child table
    frm.doc.expense_entry_account.forEach(row => {
        total_taxable_amount += row.taxable_amount || 0;
        total_vat += row.vat_amount || 0;
    });

    // Set the calculated totals
    frm.set_value('total_taxable_amount', total_taxable_amount);
    frm.set_value('total_vat', total_vat);
}

// Helper Function to Enhance the Paid Amount Field
function enhance_paid_amount_field(frm) {
    // Automatically calculate paid_amount as SUM(taxable_amount + vat_rate)
    const total_taxable_amount = frm.doc.total_taxable_amount || 0;
    const total_vat = frm.doc.total_vat || 0;
    const calculated_paid_amount = total_taxable_amount + total_vat;

    frm.set_value('paid_amount', calculated_paid_amount);

    let status = 'Not Paid';
    let color = 'rgb(255, 100, 100)'; // Light red for not paid

    if (calculated_paid_amount > 0) {
        status = 'Fully Paid';
        color = 'rgb(100, 255, 100)'; // Light green for fully paid
    }

    // Apply styles to paid_amount field dynamically
    frm.fields_dict.paid_amount.$wrapper.css({
        backgroundColor: color,
        color: '#333', // Dark text for better readability
        padding: '5px',
        borderRadius: '8px',
        fontWeight: 'bold',
        textAlign: 'center',
        transition: '0.3s ease-in-out' // Smooth hover effect
    });

    // Add tooltip with payment status
    frm.fields_dict.paid_amount.$wrapper.attr('title', `Payment Status: ${status}`);

    // Add hover effect
    frm.fields_dict.paid_amount.$wrapper.hover(
        function () {
            $(this).css('boxShadow', '0 0 8px rgba(0,0,0,0.3)');
        },
        function () {
            $(this).css('boxShadow', 'none');
        }
    );
}

frappe.ui.form.on('Expense Entry', {
    refresh: function(frm) {
        // Show the Accounting Ledger button only after the document is submitted
        if (frm.doc.__islocal || !frm.doc.docstatus || frm.doc.docstatus < 1) {
            // If the document is not submitted, hide the button
            return;
        }

        // Add the Accounting Ledger button if the document is submitted
        frm.add_custom_button(__('Accounting Ledger'), function() {
            // Check if a Journal Entry has been created
            if (!frm.doc.journal_entry_name) {
                frappe.msgprint(__('Please create a Journal Entry before accessing the General Ledger.'));
                return;
            }

            // Build the URL for the General Ledger report with dynamic filters
            let company = frm.doc.company || ''; // Use company from the Expense Entry form
            let from_date = frm.doc.date || '';   // Use date from the Expense Entry form
            let to_date = frm.doc.date || '';     // Use date from the Expense Entry form
            let voucher_no = frm.doc.journal_entry_name || ''; // Journal Entry Name to filter

            // Construct the URL with query parameters
            let url = `/app/query-report/General%20Ledger?company=${encodeURIComponent(company)}&from_date=${encodeURIComponent(from_date)}&to_date=${encodeURIComponent(to_date)}&voucher_no=${encodeURIComponent(voucher_no)}&include_dimensions=1&include_default_book_entries=1`;

            // Open the General Ledger report in a new tab
            window.open(url, '_blank');
        });
    }
});

frappe.ui.form.on('Sales Invoice', {
    after_save: function (frm) {
        if (frm.doc.docstatus === 1) {
            frappe.confirm(
                `<div style="font-size: 14px; line-height: 1.8;">
                    <strong style="color: #007BFF;">Do you want to send this invoice via WhatsApp?</strong><br>
                    <span style="color: #6C757D;">A PDF copy of the invoice will be sent to the customer.</span><br><br>
                    <strong style="color: #007BFF;">هل ترغب في إرسال هذه الفاتورة عبر الواتساب؟</strong><br>
                    <span style="color: #6C757D;">سيتم إرسال نسخة PDF من الفاتورة إلى العميل.</span>
                </div>`,
                function () {
                    send_sales_invoice_pdf_on_whatsapp(frm);
                },
                function () {
                    frappe.msgprint(__('WhatsApp message was not sent. لم يتم إرسال رسالة الواتساب.'));
                },
                {
                    primary: '📲 Send Now | إرسال الآن',
                    primary_color: '#25D366',
                    secondary: 'Not Now | ليس الآن',
                    secondary_color: '#6C757D'
                }
            );
        }
    },

    refresh: function (frm) {
        if (frm.doc.docstatus === 1) {
            frm.add_custom_button(__('📲 Send on WhatsApp | إرسال على واتساب'), function () {
                send_sales_invoice_pdf_on_whatsapp(frm);
            }).css({
                'background-color': '#25D366',
                'color': 'white',
                'font-weight': 'bold',
                'border-radius': '6px',
                'padding': '6px 12px',
                'font-size': '13px'
            });
        }
    }
});

function send_sales_invoice_pdf_on_whatsapp(frm) {
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'Customer',
            filters: { name: frm.doc.customer },
            fieldname: 'mobile_no'
        },
        callback: function (response) {
            let number = response.message ? response.message.mobile_no : null;

            if (!number) {
                frappe.msgprint(__('Customer WhatsApp number is not available. رقم واتساب العميل غير متوفر.'));
                return;
            }

            let digits = number.replace(/\D/g, '');

            // Convert to international format if local (Saudi)
            if (digits.startsWith('0')) {
                digits = '+966' + digits.slice(1);
            } else if (digits.startsWith('966')) {
                digits = '+' + digits;
            } else if (!digits.startsWith('+')) {
                digits = '+966' + digits;
            }

            if (digits.length < 12) {
                frappe.msgprint(__('Invalid WhatsApp number. رقم الواتساب غير صالح.'));
                return;
            }

            const base_url = window.location.origin;
            const pdf_url = `${base_url}/api/method/frappe.utils.print_format.download_pdf` +
                `?doctype=Sales%20Invoice&name=${encodeURIComponent(frm.doc.name)}` +
                `&format=طباعه%20pos%20مبيعات&no_letterhead=0&letterhead=Letter%20Heads&_lang=ar`;

            const message = `🧾 *Sales Invoice PDF | رابط الفاتورة:*\n${pdf_url}`;
            const whatsapp_url = `https://web.whatsapp.com/send?phone=${digits}&text=${encodeURIComponent(message)}`;

            window.open(whatsapp_url, '_blank');
        },
        error: function (error) {
            console.error('Error fetching WhatsApp number:', error);
            frappe.msgprint(__('An error occurred while fetching the WhatsApp number. حدث خطأ أثناء جلب رقم الواتساب.'));
        }
    });
}
